import stylesText from './status-pill.css?inline';
import { cssStyleSheet } from '../../utils/css.js';
import { navigate } from '../../router.js';

import './status-dot/status-dot.component.js';
import type { StatusDot } from './status-dot/status-dot.component.js';
import { ConnectivitySection } from '../status-screen/sections/connectivity/connectivity-section.component.js';
import { ServerSection } from '../status-screen/sections/server/server-section.component.js';
import { SyncSection } from '../status-screen/sections/sync/sync-section.component.js';
import { ServicesSection } from '../status-screen/sections/services/services-section.component.js';

import {
    fetchServerStatus,
    isPiGatewayReachable,
    deriveBootStage,
    type BootStage,
} from '../../services/server-control.service.js';
import { StravaService } from '../../services/strava.service.js';
import { SyncService } from '../../services/sync/sync.service.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
<button class="pill" aria-label="System status">
    <div class="dots-container">
        <status-dot id="dot-connectivity" color="gray" title="Connectivity"></status-dot>
        <status-dot id="dot-server" color="gray" title="Server"></status-dot>
        <status-dot id="dot-sync" color="gray" title="Sync"></status-dot>
        <status-dot id="dot-strava" color="gray" title="Strava"></status-dot>
    </div>
    <span class="pill-label">Initializing...</span>
</button>
`;

export class StatusPill extends HTMLElement {
    private shadow: ShadowRoot;
    private pillLabel!: HTMLSpanElement;

    // Dots
    private dotConnectivity!: StatusDot;
    private dotServer!: StatusDot;
    private dotSync!: StatusDot;
    private dotStrava!: StatusDot;

    // State
    private isOnline = navigator.onLine;
    private serverStage: BootStage = 'unreachable';
    private syncCount = 0;
    private syncError = false;
    private stravaConnected = false;

    private polling: ReturnType<typeof setTimeout> | null = null;

    private readonly onOnline = () => this.updateConnectivity(true);
    private readonly onOffline = () => this.updateConnectivity(false);

    constructor() {
        super();
        this.shadow = this.attachShadow({ mode: 'open' });
        this.shadow.adoptedStyleSheets = [styles];
        this.shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.pillLabel = this.shadow.querySelector('.pill-label')!;
        this.dotConnectivity = this.shadow.getElementById('dot-connectivity') as StatusDot;
        this.dotServer = this.shadow.getElementById('dot-server') as StatusDot;
        this.dotSync = this.shadow.getElementById('dot-sync') as StatusDot;
        this.dotStrava = this.shadow.getElementById('dot-strava') as StatusDot;

        this.shadow.querySelector('.pill')!.addEventListener('click', () => navigate('/status'));

        window.addEventListener('online', this.onOnline);
        window.addEventListener('offline', this.onOffline);

        this.updateConnectivity(navigator.onLine);
        this.schedulePoll(0);
    }

    disconnectedCallback() {
        if (this.polling) clearTimeout(this.polling);
        window.removeEventListener('online', this.onOnline);
        window.removeEventListener('offline', this.onOffline);
    }

    private schedulePoll(delayMs: number): void {
        if (this.polling) clearTimeout(this.polling);
        this.polling = setTimeout(() => void this.pollOnce(), delayMs);
    }

    private async pollOnce(): Promise<void> {
        await Promise.all([
            this.refreshServerStatus(),
            this.refreshStravaStatus(),
            this.refreshSyncStatus()
        ]);
        this.schedulePoll(30_000);
    }

    private updateConnectivity(online: boolean) {
        this.isOnline = online;
        this.updateUI();
    }

    private async refreshServerStatus(): Promise<void> {
        const reachable = await isPiGatewayReachable();
        if (!reachable) {
            this.serverStage = 'unreachable';
        } else {
            const status = await fetchServerStatus().catch(() => null);
            this.serverStage = status ? deriveBootStage(status) : 'unreachable';
        }
        this.updateUI();
    }

    private async refreshSyncStatus(): Promise<void> {
        try {
            this.syncCount = await SyncService.getPendingCount();
            this.syncError = false;
        } catch {
            this.syncError = true;
        }
        this.updateUI();
    }

    private async refreshStravaStatus(): Promise<void> {
        try {
            const status = await StravaService.getStatus();
            this.stravaConnected = status.connected;
        } catch {
            this.stravaConnected = false;
        }
        this.updateUI();
    }

    private updateUI() {
        const connectivity = ConnectivitySection.getStatus(this.isOnline);
        const server = ServerSection.getStatus(this.serverStage);
        const sync = SyncSection.getStatus(this.syncCount, this.syncError);
        const strava = ServicesSection.getStatus(this.stravaConnected);

        this.dotConnectivity.setAttribute('color', connectivity.color);
        this.dotServer.setAttribute('color', server.color);
        this.dotSync.setAttribute('color', sync.color);
        this.dotStrava.setAttribute('color', strava.color);

        if (connectivity.label) {
            this.pillLabel.textContent = connectivity.label;
        } else if (this.syncCount > 0) {
            this.pillLabel.textContent = `${this.syncCount} pending`;
        } else {
            this.pillLabel.textContent = server.label;
        }
    }
}

customElements.define('status-pill', StatusPill);
